-- PLZ-Gebiete Seed aus Übersicht_PLZ_19_02_2026.xlsx
-- Generiert am 05.03.2026

CREATE TABLE IF NOT EXISTS standort_plz_gebiete (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  standort_id UUID REFERENCES standorte(id),
  plz TEXT NOT NULL,
  franchise_name TEXT, -- Originalname aus Excel für Mapping
  created_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(plz)
);

ALTER TABLE standort_plz_gebiete ENABLE ROW LEVEL SECURITY;

CREATE POLICY "everyone_select" ON standort_plz_gebiete FOR SELECT USING (true);
CREATE POLICY "hq_modify" ON standort_plz_gebiete FOR ALL USING (
  EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND is_hq = true)
);

-- Index for fast lookup
CREATE INDEX idx_plz_gebiete_plz ON standort_plz_gebiete(plz);
CREATE INDEX idx_plz_gebiete_standort ON standort_plz_gebiete(standort_id);

